#include<bits/stdc++.h>
using namespace std;
int main(){
    int r1,r2,d;
    cin>>r1>>r2>>d;
    if(abs(r1-r2)==d&&abs(r1-r2)==0){
        cout<<"inf";
    }else if(r1+r2<d){
        cout<<4;
    }else if(abs(r1-r2)==d){
        if(r1/2==r2) cout<<1/0;
    }else if(r1+r2==d){
        cout<<3;
    }else if(abs(r1-r2)<d&&d<r1+r2){
        cout<<2;
    }else if(abs(r1-r2)>d){
        cout<<0;
    }
    return 0;
}
